var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"새로운 메뉴를 만들어야겠어. 지금 당장.","JPN":"新しいメニューを作らねば。今すぐに。","ENG":"I have to work on a new recipe. Right now.","TWN":"必須開發新的菜單！現在立刻！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"으응? 갑자기? 왜~ 오늘 모처럼 쉬는 날이잖아.","JPN":"うん？　いきなりどうしたのかしら。今日はせっかくのお休みじゃない。","ENG":"Hmm? Why? We’re off today.","TWN":"嗯？這麼突然？為什麼～難得今天休息欸？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이사 오느라 지출이 크게 늘었어.","JPN":"移転のせいで出費が大幅に増えたからな。","ENG":"It was very costly to move to this place.","TWN":"搬家花太多錢了。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이렇게라도 하지 않으면 금방 적자날 거야.","JPN":"こうでもしないとすぐに赤字になる。","ENG":"If we don’t work hard, we’ll soon end up in the red.","TWN":"不趕快想想辦法的話會出現赤字的。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그걸 바라는 건 아니겠지? 매니저?","JPN":"それは本望じゃないだろう、マネージャー？","ENG":"Or is that what you want, supervisor?","TWN":"你應該也不希望變成這樣吧？經理？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"왜 또 이렇게 심통이실까?","JPN":"どうしてこんなにご機嫌斜めなのかしら？","ENG":"Why are you being mean again?","TWN":"幹嘛又這樣咄咄逼人？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……네가 새 메뉴 개발을 안 하니까 그렇지!","JPN":"……エヴリンが新しいメニューを考えないからだろう！","ENG":"Because you’re not working on the new recipe!","TWN":"……都怪你不開發新菜單。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그렇지만 난 카페에서도 장보기며 재료 손질이며 요리며 음료 제조며 서빙이며 꼬맹이들이 청소하고 난 곳들 청소하는 거며 회계 장부 작성이며 약물 연구까지 해야 해서","JPN":"だって、私はカフェの買い出しや食材の仕込み、料理、飲み物づくり、配膳に加えて、\\nあの子たちが掃除した所のやり直しや経理業務、薬品研究までしないといけないから","ENG":"But I shop for the cooking ingredients, prepare them, fix drinks, serve customers, clean up after the kids’ mess, write in the ledger, and research on my potions...","TWN":"因為我要負責採買、備料、出菜、做飲料、招待客人，還要把她們打掃過的地方再打掃一次，收店後要作帳，還要研究藥水，"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":" 너~무 바쁜걸?","JPN":"と～っても忙しいのよ？","ENG":" I’m just TOO busy.","TWN":"很～忙欸？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……참. 그렇겠네.","JPN":"……ああ、そうだったな。","ENG":"Okay... I see.","TWN":"……哼，我就知道你會這麼說。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐, 어쩔 수 없지. 내가 신 메뉴를 개발하는 수밖에.","JPN":"まあ、しょうがない。妾が新メニューを作るしかないな。","ENG":"Well then, I’ll have to work on the new recipe myself.","TWN":"那沒辦法，只好我自己來開發新菜單囉。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"네가? 라우라 네가 메뉴 개발을 하겠다고? 흐음. 그거 아무나 하는 거 아닌데.","JPN":"あなたが？　ラウラが新メニューを作るの？　うーん、誰にでもできることじゃないけれど……","ENG":"You? Working on the new recipe? Hmm, not just anyone can do it, you know.","TWN":"你？你說你要開發菜單？呵呵，這可不是誰都能做的。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"네 생각처럼 그렇게 쉽게 뚝딱 만들어지는 게 아니란 말씀~","JPN":"思ってるほど、そう簡単に作れるものじゃないのよ～。","ENG":"It's not something you can do with a flick of your finger.","TWN":"沒你想像中那麼簡單～"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"왜 이래! 그딴 건 나한테 식은 죽 먹기라고.","JPN":"バカにするな！　それくらい、妾にとって朝飯前だ。","ENG":"Hah! It’s a piece of cake for me.","TWN":"你幹嘛！這對我來說易如反掌啦！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"감탄할 만한 신 메뉴를 만들어서 네가 요리 권한을 나한테 아예 바치도록 만들어 줄게.","JPN":"エヴリンが料理の権限を譲りたくなるような、すごい新メニューを作ってやる。","ENG":"I’ll come up with an amazing new recipe, so good that you’ll want me to do all the cooking.","TWN":"我會開發出讓你驚訝到說不出話來的新菜單，厲害到讓你交出主廚的寶座。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그건 지금이라도 당장 넘길 수 있어. 부디 가져가 줄래?","JPN":"それなら今すぐにでも譲ってあげるわよ。お願いだから、もらってくれる？","ENG":"I can do that right away. Please do take my place.","TWN":"什麼寶座你要就給你吧，拜託你現在就拿去好嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……오늘 부엌은 내가 차지할 거니까, 아무도 들어오지 마!!","JPN":"……今日は妾がキッチンを貸切る！　誰も入るなよ！！","ENG":"... I’m using the kitchen today, and I don’t want anyone to come in!","TWN":"……今天廚房是我專用的，任何人都不准進來！！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그러고 들어가서 아직도 부엌에 콕 틀어박혀 있어.","JPN":"それからずっと、キッチンに閉じこもってるのよ。","ENG":"And she’s still in the kitchen.","TWN":"說完後到現在還沒出來。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};